from __future__ import annotations

import time


class ConnectionPool:
    def __init__(self, factory, *, max_size: int, now=None, health_check=None):
        if max_size <= 0:
            raise ValueError('max_size must be positive')
        self.factory = factory
        self.max_size = max_size
        self.now = now or time.monotonic
        self.health_check = health_check
        self.idle = []

    def acquire(self):
        while self.idle:
            conn, _stamp = self.idle.pop()
            if self.health_check is None or self.health_check(conn):
                return conn
            if hasattr(conn, 'close'):
                conn.close()
        return self.factory()

    def release(self, conn):
        if len(self.idle) < self.max_size:
            self.idle.append((conn, self.now()))
        elif hasattr(conn, 'close'):
            conn.close()

    def evict_idle(self, max_idle_seconds: float):
        current = self.now()
        self.idle = [(conn, stamp) for conn, stamp in self.idle if current - stamp <= max_idle_seconds]

