from solution import ConnectionPool


class Conn:
    def __init__(self):
        self.closed = False
    def close(self):
        self.closed = True


def test_reuses_and_evicts_idle_connections():
    clock = {'t': 0.0}
    pool = ConnectionPool(Conn, max_size=1, now=lambda: clock['t'])
    conn = pool.acquire()
    pool.release(conn)
    assert pool.acquire() is conn
    pool.release(conn)
    clock['t'] = 10.0
    pool.evict_idle(5.0)
    assert conn.closed is True
